<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./path/to/skill</span></span>
